// The worker populates the task-level fields (BeadID through UsageFile).
// The parent orchestrator (LandBeadResult) populates the landing fields
// (Outcome, Status, Detail, Reason, PreserveRef, GateResults, RequiredExecSummary,
// ChecksFile) via ApplyLandingToResult before the result is written to disk or
// returned to a caller.
type ExecuteBeadResult struct {
	BeadID    string `json:"bead_id"`
	AttemptID string `json:"attempt_id,omitempty"`
	WorkerID  string `json:"worker_id,omitempty"`
	BaseRev   string `json:"base_rev"`
	ResultRev string `json:"result_rev,omitempty"`
	// ImplementationRev is the worker's own commit SHA — the candidate revision
	// produced by the agent before landing. Set from ResultRev by
	// ApplyLandResultToExecuteBeadResult before ResultRev is rewritten to the
	// branch tip. Never overwritten after first assignment.
	ImplementationRev string `json:"implementation_rev,omitempty"`
	// LandedRev is the target branch tip after the coordinator fast-forwards or
	// merges the implementation commit. Populated by ApplyLandResultToExecuteBeadResult.
	LandedRev string `json:"landed_rev,omitempty"`
	// TargetBranch is the resolved branch that received the landing. It uses the
	// landed_branch JSON name because callers care about the post-land location.
	TargetBranch string `json:"landed_branch,omitempty"`
	// EvidenceRev is the SHA of the trailing evidence commit when it differs from
	// ImplementationRev. Populated by the evidence committer; empty otherwise.
	EvidenceRev string `json:"evidence_rev,omitempty"`

	// Outcome and Status are initially set by the worker to task-level values
	// (task_succeeded / task_failed / task_no_changes), then overwritten by
	// ApplyLandingToResult with the landing decision (merged / preserved /
	// no-changes) so callers see a unified record.
	Outcome string `json:"outcome"`
	Status  string `json:"status,omitempty"`
	Detail  string `json:"detail,omitempty"`
	// OrchestratorStatus is populated after the landing/pre-merge orchestration
	// decision so result.json can distinguish worker success from final
	// non-landing outcomes.
	OrchestratorStatus string `json:"orchestrator_status,omitempty"`

	// Landing fields — populated by ApplyLandingToResult, not by ExecuteBead.
	Reason      string `json:"reason,omitempty"`
	PreserveRef string `json:"preserve_ref,omitempty"`
	// CandidateRef is the project-root git ref pinned before checks and review.
	// Format: refs/ddx/iterations/<attempt-id>/<cycle-index>.
	CandidateRef string `json:"candidate_ref,omitempty"`
	// CycleIndex is the zero-based repair-cycle index for this candidate.
	CycleIndex          int               `json:"cycle_index,omitempty"`
	GateResults         []GateCheckResult `json:"gate_results,omitempty"`
	RequiredExecSummary string            `json:"required_exec_summary,omitempty"`
	ChecksFile          string            `json:"checks_file,omitempty"`
	// Ratchet fields — populated by ApplyLandingToResult when declarative
	// ratchet thresholds were evaluated during landing. HELIX and other
	// consumers use these to distinguish ratchet-preserved attempts from
	// generic execution failures.
	RatchetEvidence []RatchetEvidence `json:"ratchet_evidence,omitempty"`
	RatchetSummary  string            `json:"ratchet_summary,omitempty"`

	// NoChangesRationale is populated when the agent wrote a rationale file to
	// the execution bundle dir inside the worktree. It carries the agent's
	// explanation of why no commits were made, and is preserved even when a
	// mixed commit + no_changes rationale is rejected.
	NoChangesRationale string `json:"no_changes_rationale,omitempty"`

	// NoEvidencePaths names worktree paths that remained dirty when the agent
	// exited without creating a commit or no_changes_rationale.txt. It helps
	// operators diagnose silent commit failures before the worktree is cleaned up.
	NoEvidencePaths []string `json:"no_evidence_paths,omitempty"`

	// CycleTrace records the append-only execution cycle trace in order.
	// Each entry captures one implementation or repair cycle.
	CycleTrace []ExecutionCycleTrace `json:"cycle_trace,omitempty"`

	// ResourceExhausted captures the root and cleanup summary when execution
	// stopped before a bead attempt because the host could not safely continue.
	ResourceExhausted any `json:"resource_exhausted,omitempty"`

	Harness                     string  `json:"harness,omitempty"`
	Provider                    string  `json:"provider,omitempty"`
	Model                       string  `json:"model,omitempty"`
	ActualPower                 int     `json:"actual_power,omitempty"`
	PredictedPower              int     `json:"predicted_power,omitempty"`
func executionCycleTraceFor(candidate CandidateResult, review *CandidateReviewResult, finalDecision string) ExecutionCycleTrace {
	reviewPresent := review != nil
	reviewVerdict := ""
	if review != nil {
		reviewVerdict = review.Verdict
	}
	audit := executionDecisionAuditForReport(candidate.Report, finalDecision, reviewPresent, reviewVerdict)
	entry := ExecutionCycleTrace{
		CycleIndex: candidate.CycleIndex,
		AttemptID:  candidate.Report.AttemptID,
		ResultRev:  candidate.Report.ResultRev,
		ImplementerRoute: ExecutionCycleRouteFacts{
			Harness:     candidate.Report.Harness,
			Provider:    candidate.Report.Provider,
			Model:       candidate.Report.Model,
			ActualPower: candidate.Report.ActualPower,
		},
		RequestedRoute: audit.RequestedRoute,
		ActualRoute:    audit.ActualRoute,
		FinalDecision:  finalDecision,
	}
	applyDecisionAuditToTrace(&entry, audit)
	if review == nil {
		return entry
	}
	entry.ReviewGroupID = strings.TrimSpace(review.ReviewGroupID)
	entry.ReviewerIndices = append([]int(nil), review.ReviewerIndices...)
	entry.ReviewVerdicts = append([]string(nil), review.ReviewerVerdicts...)
	entry.ReviewResult = ExecutionCycleReviewResult{
		Verdict:        strings.TrimSpace(review.Verdict),
		Rationale:      strings.TrimSpace(review.Rationale),
		Classification: strings.TrimSpace(review.Classification),
		PerAC:          append([]ReviewAC(nil), review.PerAC...),
		Findings:       append([]Finding(nil), review.Findings...),
	}
	return entry
}

// WriteWorktreeCandidateCycleState updates cleanup metadata and, when a
// matching run-state exists, the per-attempt run-state snapshot for a live
// candidate-cycle worktree.
func WriteWorktreeCandidateCycleState(projectRoot, wtPath, attemptID string, state CandidateCycleState) error {
	meta, err := ReadExecutionCleanupMetadata(wtPath)
	if err != nil && !errors.Is(err, os.ErrNotExist) {
		return fmt.Errorf("write candidate cycle state: read metadata: %w", err)

	t.Run("decomposed parent stale skip carries audit", func(t *testing.T) {
		var emitted map[string]any
		emitStaleCandidateSkip(func(_ string, payload map[string]any) {
			emitted = payload
		}, "ddx-niflheim-parent", &candidateSkipDecision{
			Reason: "decomposed",
			Detail: "bead is marked decomposed and execution-ineligible",
		}, &bead.Bead{
			ID:     "ddx-niflheim-parent",
			Labels: []string{"decomposed"},
			Extra:  map[string]any{bead.ExtraExecutionElig: false},
		}, "before_claim")

		require.NotNil(t, emitted)
		assert.Equal(t, "decomposed", emitted["failure_class"])
		assert.Equal(t, "operator_attention", emitted["retry_action"])
		assert.Equal(t, "skipped", emitted["review_status"])
		assert.Equal(t, "pre_claim", emitted["review_skip_reason"])
		assert.Equal(t, "not_started", emitted["land_status"])
		assert.Equal(t, "not_applicable", emitted["reconcile_status"])
	})

	t.Run("pre claim warning escalation carries audit in emitted and durable events", func(t *testing.T) {
		store, first, second := newExecuteLoopTestStore(t)
		state := &preClaimWarnRepeatState{}
		var emitted map[string]any
		emit := func(_ string, payload map[string]any) {
			emitted = payload
		}
		at := time.Unix(10, 0).UTC()
		assert.False(t, appendPreClaimIntakeWarning(store, emit, state, 2, first.ID, "worker", "system_unready", "shared readiness schema mismatch", at))
		assert.True(t, appendPreClaimIntakeWarning(store, emit, state, 2, second.ID, "worker", "system_unready", "shared readiness schema mismatch", at.Add(time.Second)))

		require.NotNil(t, emitted)
		assert.Equal(t, "preclaim_warn_repeated", emitted["failure_class"])
		assert.Equal(t, "operator_attention", emitted["retry_action"])
		assert.Equal(t, float64(2), numericAny(emitted["escalation_count"]))
		assert.Equal(t, "skipped", emitted["review_status"])
		assert.Equal(t, "pre_claim", emitted["review_skip_reason"])
		assert.Equal(t, "not_started", emitted["land_status"])

		events, err := store.Events(second.ID)
		require.NoError(t, err)
		var durable map[string]any
		for _, event := range events {
			if event.Kind != "operator_attention" {
				continue
			}
			require.NoError(t, json.Unmarshal([]byte(event.Body), &durable))
			break
		}
		require.NotNil(t, durable)
		assert.Equal(t, "preclaim_warn_repeated", durable["failure_class"])
		assert.Equal(t, "operator_attention", durable["retry_action"])
		assert.Equal(t, "pre_claim", durable["review_skip_reason"])
	})
}

func firstCycleTrace(t *testing.T, result map[string]any) map[string]any {
	t.Helper()
	rawTrace, ok := result["cycle_trace"].([]any)
	require.True(t, ok)
	require.NotEmpty(t, rawTrace)
	cycle, ok := rawTrace[0].(map[string]any)
	require.True(t, ok)
	return cycle
}

func decisionAuditFromEventBody(t *testing.T, body string) map[string]any {
	t.Helper()
	for _, line := range strings.Split(body, "\n") {
		raw, ok := strings.CutPrefix(line, "decision_audit=")
		if !ok {
			continue
		}
		var audit map[string]any
		require.NoError(t, json.Unmarshal([]byte(raw), &audit))
		return audit
	}
	t.Fatalf("decision_audit line missing from event body:\n%s", body)
	return nil
}

func nestedString(t *testing.T, parent map[string]any, objectKey, valueKey string) string {
	t.Helper()
	obj, ok := parent[objectKey].(map[string]any)
	require.True(t, ok, "%s must be an object", objectKey)
	value, _ := obj[valueKey].(string)
	return value
}

func numericAny(value any) float64 {
	switch v := value.(type) {
	case int:
		return float64(v)
	case float64:
		return v
	default:
		return 0
	}
}

